// src/pages/HomeScreen.js
import React, { useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TouchableOpacity,
} from "react-native";
import { useNavigation } from "@react-navigation/native";

// ✅ DO NOT TOUCH: taxi.png already includes arch + big green pin + taxi
const taxiImg = require("../../assets/taxi.png");

// ✅ urban.png already includes crest + “Communauté Urbaine de Yaoundé”
const cityLogo = require("../../assets/urban.png");

const tickCircle = require("../../assets/tickcircle.png");
const shieldLock = require("../../assets/shieldd.png");

export default function HomeScreen() {
  const navigation = useNavigation();
  const plateNumber = "CE696KO";

  // ✅ Language state (simple, local)
  const [lang, setLang] = useState("fr");

  const copy = {
    fr: {
      verified: "Vérifié",
      officialControl: "Contrôle officiel",
    },
    en: {
      verified: "Verified",
      officialControl: "Official control",
    },
  };

  const T = copy[lang];

  const goToOfficialControl = () => {
    // Home is the only screen for now
    // navigation.navigate("official-control");
  };

  return (
    <SafeAreaView style={styles.safe}>
      <View style={styles.screen}>

        {/* ===== Language Switch ===== */}
        <View style={styles.langRow}>
          <TouchableOpacity
            onPress={() => setLang("fr")}
            style={[styles.langPill, lang === "fr" && styles.langPillActive]}
          >
            <Text style={[styles.langText, lang === "fr" && styles.langTextActive]}>
              FR
            </Text>
          </TouchableOpacity>

          <TouchableOpacity
            onPress={() => setLang("en")}
            style={[styles.langPill, lang === "en" && styles.langPillActive]}
          >
            <Text style={[styles.langText, lang === "en" && styles.langTextActive]}>
              EN
            </Text>
          </TouchableOpacity>
        </View>

        {/* ===== HERO (UNCHANGED) ===== */}
        <View style={styles.heroWrap}>
          <Image source={taxiImg} style={styles.taxi} resizeMode="contain" />
        </View>

        {/* ===== Vérifié / Verified ===== */}
        <View style={styles.statusRow}>
          <Image source={tickCircle} style={styles.smallTick} resizeMode="contain" />
          <Text style={styles.statusText}>{T.verified}</Text>
        </View>

        {/* ===== Plate ===== */}
        <View style={styles.plateWrap}>
          <View style={styles.plateBox}>
            <Text style={styles.plateText}>{plateNumber}</Text>
          </View>
        </View>

        {/* ===== Button ===== */}
        <TouchableOpacity
          activeOpacity={0.92}
          style={styles.officialBtn}
          onPress={goToOfficialControl}
        >
          <Image source={shieldLock} style={styles.btnIcon} resizeMode="contain" />
          <Text style={styles.btnText}>{T.officialControl}</Text>
        </TouchableOpacity>

        {/* ===== Bottom logo ===== */}
        <View style={styles.logoWrap}>
          <Image source={cityLogo} style={styles.logo} resizeMode="contain" />
        </View>
      </View>
    </SafeAreaView>
  );
}

const PLATE_WIDTH = 220;
const PLATE_HEIGHT = 40;

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#F5F5F5" },

  screen: {
    flex: 1,
    paddingTop: 14,
    paddingHorizontal: 18,
    alignItems: "center",
    justifyContent: "flex-start",
  },

  /* ===== Language switch ===== */
  langRow: {
    width: "100%",
    flexDirection: "row",
    justifyContent: "flex-end",
    gap: 8,
    marginBottom: 6,
  },
  langPill: {
    height: 28,
    paddingHorizontal: 12,
    borderRadius: 16,
    backgroundColor: "rgba(0,0,0,0.08)",
    alignItems: "center",
    justifyContent: "center",
  },
  langPillActive: {
    backgroundColor: DARK_GREEN,
  },
  langText: {
    fontSize: 13,
    fontWeight: "700",
    color: "#111827",
  },
  langTextActive: {
    color: "#FFFFFF",
  },

  /* ===== HERO ===== */
  heroWrap: {
    width: "100%",
    alignItems: "center",
    justifyContent: "center",
    marginTop: 1,
  },
  taxi: {
    width: "100%",
    height: 200,
  },

  /* ===== STATUS ===== */
  statusRow: {
    flexDirection: "row",
    alignItems: "center",
    marginTop: 1,
    gap: 12,
  },
  smallTick: { width: 56, height: 56 },
  statusText: {
    fontSize: 30,
    fontWeight: "600",
    color: GREEN,
  },

  /* ===== PLATE ===== */
  plateWrap: {
    marginTop: 10,
    alignItems: "center",
  },
  plateBox: {
    width: PLATE_WIDTH,
    height: PLATE_HEIGHT,
    borderRadius: 16,
    borderWidth: 3,
    borderColor: GREEN,
    backgroundColor: "#FFFFFF",
    alignItems: "center",
    justifyContent: "center",
  },
  plateText: {
    fontSize: 30,
    fontWeight: "600",
    letterSpacing: 1,
    color: "#111827",
  },

  /* ===== BUTTON ===== */
  officialBtn: {
    marginTop: 12,
    width: "72%",
    height: 40,
    backgroundColor: DARK_GREEN,
    borderRadius: 16,
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    paddingLeft: 54,
    paddingRight: 16,
    shadowColor: "#000",
    shadowOpacity: 0.2,
    shadowRadius: 16,
    shadowOffset: { width: 0, height: 12 },
    elevation: 7,
  },
  btnIcon: {
    position: "absolute",
    left: 16,
    width: 30,
    height: 30,
  },
  btnText: {
    color: "#FFFFFF",
    fontSize: 20,
    fontWeight: "700",
  },

  /* ===== LOGO ===== */
  logoWrap: {
    marginTop: 10,
    alignItems: "center",
    width: "100%",
    flex: 1,
  },
  logo: {
    width: 220,
    height: 210,
  },
});
